local function fullUnload()
    M.coreUnload()
    if Toggles then
        if Toggles.FlyEnabled      then pcall(function() Toggles.FlyEnabled:SetValue(false)     end) end
        if Toggles.AutoSpawnToggle then pcall(function() Toggles.AutoSpawnToggle:SetValue(false) end) end
        if Toggles.AccelEnabled    then pcall(function() Toggles.AccelEnabled:SetValue(false)    end) end
        if Toggles.WSEnabled       then pcall(function() Toggles.WSEnabled:SetValue(false)       end) end
    end
    Library:Unload()
end

Right:AddButton("Unload", function() fullUnload() end)

game:GetService("UserInputService").InputBegan:Connect(function(input, gp)
    if gp then return end
    if input.KeyCode == Enum.KeyCode.F then
        if Config.FlyEnabled then M.stopFly() else M.startFly() end
        if Toggles and Toggles.FlyEnabled then
            Toggles.FlyEnabled:SetValue(Config.FlyEnabled)
        end
    end
end)

